import React, { useEffect, useState } from 'react';
import { employeesAPI, deptAPI, authAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Select, Badge, toast, Avatar,
} from '../components/ui';
import { Plus, Eye } from 'lucide-react';

export default function Employees() {
  const [employees, setEmployees] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [showView, setShowView] = useState(null);
  const [creating, setCreating] = useState(false);
  const [form, setForm] = useState({
    email: '', password: '', role_name: 'employee',
    first_name: '', last_name: '', employee_id: '',
    date_of_joining: '', department_id: '',
  });

  const load = async () => {
    setLoading(true);
    try {
      const [empRes, deptRes] = await Promise.all([
        employeesAPI.list(),
        deptAPI.list(),
      ]);
      setEmployees(empRes.data);
      setDepartments(deptRes.data);
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load employees', 'error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const resetForm = () => setForm({
    email: '', password: '', role_name: 'employee',
    first_name: '', last_name: '', employee_id: '',
    date_of_joining: '', department_id: '',
  });

  const getDeptName = (id) => departments.find((d) => d.id === id)?.name || '—';

  const handleCreate = async (e) => {
    e.preventDefault();
    setCreating(true);
    try {
      // Step 1: Register user account
      const { data: regData } = await authAPI.register({
        email: form.email,
        password: form.password,
        role_name: form.role_name,
      });

      // Step 2: Create employee linked to user
      await employeesAPI.create({
        first_name: form.first_name,
        last_name: form.last_name,
        employee_id: form.employee_id,
        date_of_joining: form.date_of_joining,
        department_id: form.department_id ? parseInt(form.department_id) : null,
        user_id: regData.user_id,
      });

      toast('Employee created successfully', 'success');
      setShowCreate(false);
      resetForm();
      load();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to create employee', 'error');
    } finally {
      setCreating(false);
    }
  };

  const cols = [
    {
      key: 'employee_id',
      label: 'Emp ID',
      render: (r) => (
        <span style={{ fontWeight: 600, color: 'var(--primary)', fontSize: 13 }}>
          {r.employee_id}
        </span>
      ),
    },
    {
      key: 'name',
      label: 'Name',
      render: (r) => (
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <Avatar name={`${r.first_name} ${r.last_name}`} size={32} />
          <div>
            <div style={{ fontWeight: 500 }}>{r.first_name} {r.last_name}</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{r.email}</div>
          </div>
        </div>
      ),
    },
    {
      key: 'department',
      label: 'Department',
      render: (r) => getDeptName(r.department_id),
    },
    {
      key: 'date_of_joining',
      label: 'Date Joined',
      render: (r) => r.date_of_joining || '—',
    },
    {
      key: 'status',
      label: 'Status',
      render: () => <Badge variant="success">Active</Badge>,
    },
    {
      key: 'actions',
      label: 'Actions',
      render: (r) => (
        <Btn variant="ghost" size="xs" onClick={() => setShowView(r)}>
          <Eye size={15} /> View
        </Btn>
      ),
    },
  ];

  return (
    <>
      <PageHeader
        title="Employees"
        subtitle="Manage all employee records"
        actions={
          <Btn onClick={() => { resetForm(); setShowCreate(true); }}>
            <Plus size={16} /> Add Employee
          </Btn>
        }
      />

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <Table cols={cols} rows={employees} loading={loading} emptyMsg="No employees found" />
      </Card>

      {/* Create Employee Modal */}
      <Modal open={showCreate} onClose={() => setShowCreate(false)} title="Add New Employee" width={560}>
        <form onSubmit={handleCreate}>
          <h4
            style={{
              fontSize: 12,
              color: 'var(--text-muted)',
              textTransform: 'uppercase',
              letterSpacing: '0.06em',
              marginBottom: 14,
              paddingBottom: 8,
              borderBottom: '1px solid var(--border-light)',
            }}
          >
            Login Account
          </h4>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="Email"
              type="email"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              required
              id="emp-email"
            />
            <Input
              label="Password"
              type="password"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              required
              id="emp-password"
            />
          </div>
          <Select
            label="Role"
            value={form.role_name}
            onChange={(e) => setForm({ ...form, role_name: e.target.value })}
            id="emp-role"
          >
            <option value="employee">Employee</option>
            <option value="hr">HR</option>
            <option value="department_head">Department Head</option>
            <option value="accountant">Accountant</option>
            <option value="admin">Admin</option>
          </Select>

          <h4
            style={{
              fontSize: 12,
              color: 'var(--text-muted)',
              textTransform: 'uppercase',
              letterSpacing: '0.06em',
              marginBottom: 14,
              marginTop: 8,
              paddingBottom: 8,
              borderBottom: '1px solid var(--border-light)',
            }}
          >
            Employee Profile
          </h4>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="First Name"
              value={form.first_name}
              onChange={(e) => setForm({ ...form, first_name: e.target.value })}
              required
              id="emp-first-name"
            />
            <Input
              label="Last Name"
              value={form.last_name}
              onChange={(e) => setForm({ ...form, last_name: e.target.value })}
              required
              id="emp-last-name"
            />
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="Employee ID"
              value={form.employee_id}
              onChange={(e) => setForm({ ...form, employee_id: e.target.value })}
              placeholder="e.g. EMP001"
              required
              id="emp-id-field"
            />
            <Input
              label="Date of Joining"
              type="date"
              value={form.date_of_joining}
              onChange={(e) => setForm({ ...form, date_of_joining: e.target.value })}
              required
              id="emp-doj"
            />
          </div>
          <Select
            label="Department"
            value={form.department_id}
            onChange={(e) => setForm({ ...form, department_id: e.target.value })}
            id="emp-department"
          >
            <option value="">Select Department</option>
            {departments.map((d) => (
              <option key={d.id} value={d.id}>{d.name}</option>
            ))}
          </Select>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowCreate(false)}>Cancel</Btn>
            <Btn type="submit" loading={creating}>Create Employee</Btn>
          </div>
        </form>
      </Modal>

      {/* View Employee Modal */}
      <Modal open={!!showView} onClose={() => setShowView(null)} title="Employee Details" width={440}>
        {showView && (
          <div style={{ textAlign: 'center' }}>
            <Avatar
              name={`${showView.first_name} ${showView.last_name}`}
              size={72}
              style={{ margin: '0 auto 16px' }}
            />
            <h2 style={{ fontSize: 20, marginBottom: 4 }}>
              {showView.first_name} {showView.last_name}
            </h2>
            <p style={{ color: 'var(--text-muted)', fontSize: 14, marginBottom: 20 }}>
              {showView.email}
            </p>

            <div
              style={{
                background: 'var(--surface-2)',
                borderRadius: 'var(--radius-lg)',
                padding: 20,
                textAlign: 'left',
              }}
            >
              {[
                ['Employee ID', showView.employee_id],
                ['Department', getDeptName(showView.department_id)],
                ['Date of Joining', showView.date_of_joining],
              ].map(([k, v]) => (
                <div
                  key={k}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    padding: '10px 0',
                    borderBottom: '1px solid var(--border-light)',
                    fontSize: 14,
                  }}
                >
                  <span style={{ color: 'var(--text-muted)' }}>{k}</span>
                  <span style={{ fontWeight: 500 }}>{v || '—'}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </Modal>
    </>
  );
}
